import { getToken } from "./auth";
import type { Ticket, TicketPayload } from "./types";

const apiBaseUrl = process.env.NEXT_PUBLIC_API_BASE_URL ?? "http://localhost:8000";

type ApiError = {
  detail?: string;
};

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const response = await fetch(`${apiBaseUrl}${path}`, {
    ...init,
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${getToken()}`,
      ...(init?.headers ?? {}),
    },
    cache: "no-store",
  });

  if (!response.ok) {
    const error = (await response.json().catch(() => ({}))) as ApiError;
    throw new Error(error.detail ?? "通信に失敗しました。");
  }

  if (response.status === 204) {
    return undefined as T;
  }

  return (await response.json()) as T;
}

export async function login(email: string, password: string) {
  return request<{ access_token: string; token_type: string }>("/api/auth/login", {
    method: "POST",
    body: JSON.stringify({ email, password }),
  });
}

export async function fetchTickets(searchParams: URLSearchParams) {
  const query = searchParams.toString();
  return request<Ticket[]>(`/api/tickets${query ? `?${query}` : ""}`);
}

export async function fetchTicket(id: number) {
  return request<Ticket>(`/api/tickets/${id}`);
}

export async function createTicket(payload: TicketPayload) {
  return request<Ticket>("/api/tickets", {
    method: "POST",
    body: JSON.stringify(normalizePayload(payload)),
  });
}

export async function updateTicket(id: number, payload: TicketPayload) {
  return request<Ticket>(`/api/tickets/${id}`, {
    method: "PUT",
    body: JSON.stringify(normalizePayload(payload)),
  });
}

export async function deleteTicket(id: number) {
  return request<void>(`/api/tickets/${id}`, {
    method: "DELETE",
  });
}

function normalizePayload(payload: TicketPayload) {
  return {
    ...payload,
    description: payload.description.trim() || null,
    due_date: payload.due_date || null,
  };
}

